qry:select.qry:xquery:
				for $r in sql('
				SELECT
					LIQ97_PERSONAL_EMP.e_numero_legajo, 
					LIQ96_CONCEPTOS.c_tipo_concepto,
					SUM(LIQ20_CONC_LIQ_PER.n_valor) AS n_valor, 
					MAX(LIQ97_PERSONAL_EMP.d_ape_y_nom) AS d_ape_y_nom,
					max(LIQ19_LIQUIDACION.d_titulo) as d_titulo,
					LIQ99_LIQUIDACION.e_periodo
					{%? (#PARAMIN:@c_agrupacion='ubicacion') 
						{% ,LIQ97_PERSONAL_EMP.c_ubicacion %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='obra') 
						{% ,LIQ97_PERSONAL_EMP.c_obra_social %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='sindicato') 
						{% ,LIQ97_PERSONAL_EMP.c_sindicato %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='convenio') 
						{% ,LIQ97_PERSONAL_EMP.c_convenio %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='categ') 
						{% ,LIQ97_PERSONAL_EMP.c_categoria_ult %} 
						{% %} 
					%}			
				FROM 
					LIQ20_TOT_LIQ_PER, 
					LIQ99_RECIBOS, 
					LIQ97_PERSONAL_EMP, 
					LIQ20_CONC_LIQ_PER,
					LIQ96_CONCEPTOS,
					LIQ99_LIQUIDACION,
					LIQ01_TIPOS_LIQ,
					PER02_PERSONAL_EMP,
					LIQ19_EJECUCIONES,
					LIQ19_LIQUIDACION,
					ORG03_EMPRESAS
				JOIN
					LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per,
					LIQ20_CONC_LIQ_PER.oi_concepto_ddo INNER LIQ96_CONCEPTOS.oi_concepto_ddo,
					LIQ99_RECIBOS.oi_liquidacion_ddo INNER LIQ99_LIQUIDACION.oi_liquidacion_ddo,					
					LIQ01_TIPOS_LIQ.c_tipo_liq INNER LIQ99_LIQUIDACION.c_tipo_liq,
					LIQ99_RECIBOS.e_numero_legajo INNER PER02_PERSONAL_EMP.e_numero_legajo,
				  LIQ99_LIQUIDACION.oi_liquidacion_ddo INNER LIQ19_EJECUCIONES.oi_liquidacion_ddo,
				  LIQ19_LIQUIDACION.oi_liquidacion INNER LIQ19_EJECUCIONES.oi_liquidacion,
				  LIQ99_LIQUIDACION.c_empresa INNER ORG03_EMPRESAS.c_empresa,
					PER02_PERSONAL_EMP.oi_empresa INNER ORG03_EMPRESAS.oi_empresa,
					LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ99_RECIBOS.oi_tot_liq_per,
					LIQ20_TOT_LIQ_PER.oi_tot_liq_per INNER LIQ20_CONC_LIQ_PER.oi_tot_liq_per,
					LIQ20_TOT_LIQ_PER.oi_per_emp_ddo INNER LIQ97_PERSONAL_EMP.oi_per_emp_ddo
				WHERE
					LIQ20_CONC_LIQ_PER.n_valor != 0.00 AND
					PER02_PERSONAL_EMP.oi_empresa = {#PARAMIN:@oi_empresa} AND
					LIQ99_LIQUIDACION.e_periodo = {#SOURCE:@value} AND

					LIQ99_LIQUIDACION.c_estado = \'F\' AND
					LIQ96_CONCEPTOS.c_tipo_concepto in (0,1,2,3,4,7,8)
					{%? (#UBICACION:@c_ubicaciondesde!='') 
  					{% AND LIQ97_PERSONAL_EMP.c_ubicacion >= {#UBICACION:@c_ubicaciondesde} 
  					%} 
  				{%  %}
  				%}
  				{%? (#UBICACION:@c_ubicacionhasta!='') 
    				{% AND LIQ97_PERSONAL_EMP.c_ubicacion <= {#UBICACION:@c_ubicacionhasta} 
  					%} 
  				{%  %}
  				%}

					{%? (#PARAMIN:@c_agrupacion='ubicacion') 
						{% AND LIQ97_PERSONAL_EMP.c_ubicacion = {#AGRUP:@c_ubicacion} %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='obra') 
						{% AND LIQ97_PERSONAL_EMP.c_obra_social = {#AGRUP:@c_obra_social} %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='sindicato') 
						{% AND LIQ97_PERSONAL_EMP.c_sindicato = {#AGRUP:@c_sindicato} %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='convenio') 
						{% AND LIQ97_PERSONAL_EMP.c_convenio = {#AGRUP:@c_convenio} %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='categ') 
						{% AND LIQ97_PERSONAL_EMP.c_categoria_ult = {#AGRUP:@c_categoria} %} 
						{% %} 
					%}
          {%? (#PARAMIN:@cod_desde!='') 
  					{% AND STRING2NUMBER(LIQ96_CONCEPTOS.c_concepto) >= {#PARAMIN:@cod_desde} 
  				%} 
  					{%  %}
  				%}
  				{%? (#PARAMIN:@cod_hasta!='') 
  					{% AND STRING2NUMBER(LIQ96_CONCEPTOS.c_concepto) <= {#PARAMIN:@cod_hasta} 
  				%} 
  					{%  %}
  				%}
				  					{%? (string(#PARAMIN:TIPOS/C/@id)!='') 
						{% AND LIQ01_TIPOS_LIQ.oi_tipo_liq in ({%=string(#PARAMIN:TIPOS/C/@id) %}) %} 
						{% %} 
					%}

					{%? (#PARAMIN:@oi_liquidacionFIL!='') 
					  {% and LIQ19_EJECUCIONES.oi_liquidacion = {#PARAMIN:@oi_liquidacionFIL} %} 
					  {% %} 
					%}
					{%? (string(#LEGAJOS:ROW/@id)!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#LEGAJOS:ROW/@id) %}) %} {% %} %}
				GROUP BY
					LIQ99_LIQUIDACION.e_periodo,
					LIQ97_PERSONAL_EMP.e_numero_legajo,
					LIQ96_CONCEPTOS.c_tipo_concepto 
					{%? (#PARAMIN:@c_agrupacion='ubicacion') 
						{% , LIQ97_PERSONAL_EMP.c_ubicacion  %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='obra') 
						{% , LIQ97_PERSONAL_EMP.c_obra_social  %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='sindicato') 
						{% , LIQ97_PERSONAL_EMP.c_sindicato %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='convenio') 
						{% , LIQ97_PERSONAL_EMP.c_convenio %} 
						{% %} 
					%}
					{%? (#PARAMIN:@c_agrupacion='categ') 
						{% , LIQ97_PERSONAL_EMP.c_categoria_ult %} 
						{% %} 
					%}

				ORDER BY e_numero_legajo ASC
			')/ROWS/ROW
